import{l as e,a as r,c as t,aj as i}from"./chunks/framework.CyPZ6aEA.js";const u=JSON.parse('{"title":"gstack 技能体验","description":"","frontmatter":{},"headers":[],"relativePath":"ai/gstack-skills.md","filePath":"ai/gstack-skills.md"}'),o={name:"ai/gstack-skills.md"};function l(s,a,n,h,c,p){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="gstack-技能体验" tabindex="-1">gstack 技能体验 <a class="header-anchor" href="#gstack-技能体验" aria-label="Permalink to &quot;gstack 技能体验&quot;">​</a></h1><h2 id="why" tabindex="-1">why <a class="header-anchor" href="#why" aria-label="Permalink to &quot;why&quot;">​</a></h2><p><a href="https://github.com/garrytan/gstack#the-sprint" target="_blank" rel="noreferrer">garrytan/gstack</a> 中的技能，构建了一套高效开发流程：思考 → 规划 → 构建 → 审查 → 测试 → 交付 → 反思</p><p>前一个技能的输出，会在后一个技能中衔接使用。</p><p>gstack 还积极地引入新出现的工具，如：pretext 文字内容排版响应式、andrej-karpathy-skills 开发四原则</p><h2 id="what" tabindex="-1">what <a class="header-anchor" href="#what" aria-label="Permalink to &quot;what&quot;">​</a></h2><h3 id="office-hours" tabindex="-1">office-hours <a class="header-anchor" href="#office-hours" aria-label="Permalink to &quot;office-hours&quot;">​</a></h3><p>定义产品：梳理我对产品解决的痛点，然后给出问题、调整、评估、撰写设计文档。</p><p>由“功能驱动”转为“痛点驱动”，最终开发是不仅实现了功能，而且更好地解决了痛点。</p><h3 id="autoplan" tabindex="-1">autoplan <a class="header-anchor" href="#autoplan" aria-label="Permalink to &quot;autoplan&quot;">​</a></h3><p>自动运行全部 plan-xx-review 技能：ceo -&gt; design -&gt; eng -&gt; dx</p><h3 id="plan-ceo-review" tabindex="-1">plan-ceo-review <a class="header-anchor" href="#plan-ceo-review" aria-label="Permalink to &quot;plan-ceo-review&quot;">​</a></h3><p>重新思考问题：对设计文档进行详细审查，发现需求中潜在的十星级产品。</p><p>从市场和优先级的角度来选择需求切入点：扩大需求范围、缩减需求范围，避免过度设计。并给出人工开发对比辅助开发的时间成本。</p><h3 id="plan-eng-review" tabindex="-1">plan-eng-review <a class="header-anchor" href="#plan-eng-review" aria-label="Permalink to &quot;plan-eng-review&quot;">​</a></h3><p>制定架构、数据流、图表、边界情况和测试用例，最后让我来判断计划方案是否通过。通过后开始开发。</p><blockquote><p>👍提前分析开发中可能遇到的问题。</p></blockquote><h3 id="review" tabindex="-1">review <a class="header-anchor" href="#review" aria-label="Permalink to &quot;review&quot;">​</a></h3><p>修复问题，发现能通过代码检查但是存在逻辑错误的、影响使用的问题。</p><h3 id="qa" tabindex="-1">qa <a class="header-anchor" href="#qa" aria-label="Permalink to &quot;qa&quot;">​</a></h3><p>浏览器中自动化测试，发现并修复问题。</p><p>启动的浏览器能持久化 cookie 和登录状态。</p><h3 id="ship" tabindex="-1">ship <a class="header-anchor" href="#ship" aria-label="Permalink to &quot;ship&quot;">​</a></h3><p>测试验证 review 中发现的问题，提交 PR</p><h3 id="learn" tabindex="-1">learn <a class="header-anchor" href="#learn" aria-label="Permalink to &quot;learn&quot;">​</a></h3><p>记忆对话中学习到的知识，包含：项目相关的模式、陷阱和偏好。保存到 learnings.jsonl 中</p><h3 id="investigate" tabindex="-1">investigate <a class="header-anchor" href="#investigate" aria-label="Permalink to &quot;investigate&quot;">​</a></h3><p>查找问题根因，根据假设逐个验证找到根因，才会停下。</p><h3 id="setup-browser-cookies" tabindex="-1">setup-browser-cookies <a class="header-anchor" href="#setup-browser-cookies" aria-label="Permalink to &quot;setup-browser-cookies&quot;">​</a></h3><p>从 chromium 浏览器中导入 cookies，复用之前的登录状态。</p>',30)])])}const k=e(o,[["render",l]]);export{u as __pageData,k as default};
